# scapy.contrib.description = SAE J1939 SPN database
# scapy.contrib.status = skip

"""
SAE J1939 Suspect Parameter Number (SPN) definitions.

Data sourced from SAE J1939-71 (Surface Vehicle Recommended Practice).
Each entry is a :class:`J1939SPNDef` namedtuple with the fields:

* ``spn`` – SPN number (int)
* ``pgn`` – PGN this SPN belongs to (int)
* ``bit_position_start`` – bit position within the PGN data (int)
* ``spn_length`` – field width in bits (int) or ``'variable'``
* ``spn_name`` – short human-readable name (str)
* ``units`` – engineering units string (str)
* ``resolution_num`` – resolution numerator (float)
* ``resolution_den`` – resolution denominator (float)
* ``offset`` – value offset (float)
* ``data_range_lower`` – lower bound of valid data range (float)
* ``data_range_upper`` – upper bound of valid data range (float)
"""

from typing import NamedTuple, Union


class J1939SPNDef(NamedTuple):
    spn: int
    pgn: int
    bit_position_start: int
    spn_length: Union[int, str]
    spn_name: str
    units: str
    resolution_num: float
    resolution_den: float
    offset: float
    data_range_lower: float
    data_range_upper: float


